import 'package:baseball_detector_flutter/controllers/ai_coach_report_controller.dart';
import 'package:baseball_detector_flutter/controllers/resource_data_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/session_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/team_list_controller.dart';
import 'package:baseball_detector_flutter/data/models/session.dart';
import 'package:baseball_detector_flutter/data/result.dart';
import 'package:flutter/material.dart';
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

Future<void> Function() useSessionRefresh({
  required WidgetRef ref,
  required String teamId,
  required ValueNotifier<Session> currentSession,
}) {
  return useCallback(() async {
    final res = await ref
        .read(sessionListControllerProvider.notifier)
        .refreshSpecificSesison(
            teamId: teamId, sessionId: currentSession.value.id!);

    if (res.hasRight) {
      currentSession.value = res.right;

      final reportId = res.right.aiCoachReport?.id;
      if (reportId != null) {
        ref.invalidate(
          aICoachReportControllerProvider(
            teamId: teamId,
            reportId: reportId,
          ),
        );
      }
    }

    ref
        .read(resourceDataListControllerProvider(
          teamId: teamId,
          sessionId: currentSession.value.id!,
        ).notifier)
        .forceRefresh();

    ref.invalidate(teamListControllerProvider);

    await ref.read(resourceDataListControllerProvider(
      teamId: teamId,
      sessionId: currentSession.value.id!,
    ).future);
  }, [teamId, currentSession]);
}

